def solve(grid):
    import numpy as np
    grid = np.array(grid)
    H, W = grid.shape
    output = np.zeros_like(grid)

    def find_processable_lines(grid, axis):
        """axis=0 means rows, axis=1 means columns"""
        lines = []
        if axis == 0:
            length = W
            n_lines = H
        else:
            length = H
            n_lines = W

        for i in range(n_lines):
            if axis == 0:
                line = grid[i, :]
            else:
                line = grid[:, i]

            nonzero = [(int(j), int(line[j])) for j in range(len(line)) if line[j] != 0]
            if len(nonzero) < 2 or len(nonzero) > 3:
                continue

            # Find pairs of same color
            from collections import Counter
            colors = [c for _, c in nonzero]
            color_counts = Counter(colors)

            pair_color = None
            for c, cnt in color_counts.items():
                if cnt == 2:
                    pair_color = c
                    break

            if pair_color is None:
                continue

            # Check that remaining cells (if any) are exactly 1 cell of different color
            others = [(j, c) for j, c in nonzero if c != pair_color]
            if len(others) > 1:
                continue

            pair_positions = [j for j, c in nonzero if c == pair_color]
            marker = others[0] if others else None

            lines.append((i, pair_color, pair_positions, marker))

        return lines

    # Try both directions, pick the one with more processable lines
    row_lines = find_processable_lines(grid, 0)
    col_lines = find_processable_lines(grid, 1)

    if len(row_lines) >= len(col_lines):
        axis = 0
        lines = row_lines
    else:
        axis = 1
        lines = col_lines

    for line_idx, pair_color, pair_pos, marker in lines:
        p0, p1 = pair_pos[0], pair_pos[1]
        period = abs(p1 - p0)
        phase = p0 % period

        if axis == 0:
            length = W
        else:
            length = H

        if marker is not None:
            marker_pos, marker_color = marker
            # Check if marker is on pattern
            if marker_pos % period == phase:
                # On-pattern: tile from min to max of all positions, color changes
                all_pos = pair_pos + [marker_pos]
                lo, hi = min(all_pos), max(all_pos)
                color = marker_color
                for j in range(lo, hi + 1):
                    if j % period == phase:
                        if axis == 0:
                            output[line_idx, j] = color
                        else:
                            output[j, line_idx] = color
            else:
                # Off-pattern: tile fully, marker persists
                color = pair_color
                for j in range(length):
                    if j % period == phase:
                        if axis == 0:
                            output[line_idx, j] = color
                        else:
                            output[j, line_idx] = color
                # Write marker
                if axis == 0:
                    output[line_idx, marker_pos] = marker_color
                else:
                    output[marker_pos, line_idx] = marker_color
        else:
            # No marker: tile fully
            color = pair_color
            for j in range(length):
                if j % period == phase:
                    if axis == 0:
                        output[line_idx, j] = color
                    else:
                        output[j, line_idx] = color

    return output.tolist()

# Test on training examples
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Example {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        result = np.array(result)
        expected = np.array(expected)
        diff = np.argwhere(result != expected)
        print(f"  Differences at {len(diff)} positions")
        for r, c in diff[:10]:
            print(f"    ({int(r)},{int(c)}): got {int(result[r,c])}, expected {int(expected[r,c])}")

